import{_ as e,c as t,o as r,ag as o}from"./chunks/framework.KLbWPeN7.js";const u=JSON.parse('{"title":"VPS自建中转矿池教程","description":"","frontmatter":{"title":"VPS自建中转矿池教程","date":"2025-05-07T00:00:00.000Z","sidebar":"auto"},"headers":[],"relativePath":"mining-guides/自建矿池中转.md","filePath":"mining-guides/自建矿池中转.md"}'),i={name:"mining-guides/自建矿池中转.md"};function p(d,a,s,n,l,_){return r(),t("div",null,a[0]||(a[0]=[o('<h1 id="解决矿池连接问题-自建中转教程" tabindex="-1">解决矿池连接问题，自建中转教程 <a class="header-anchor" href="#解决矿池连接问题-自建中转教程" aria-label="Permalink to &quot;解决矿池连接问题，自建中转教程&quot;">​</a></h1><p>自建中转简单高效，目前各大矿池国内DNS基本被污染无法请求， 可搭建香港服务器转发数据解决该问题</p><h2 id="选配服务器" tabindex="-1">选配服务器 <a class="header-anchor" href="#选配服务器" aria-label="Permalink to &quot;选配服务器&quot;">​</a></h2><p>国内推荐腾讯云和阿里云的香港服务器 登录成功后进入命令行界面</p><h2 id="_1、安装启动端口转发服务" tabindex="-1">1、安装启动端口转发服务 <a class="header-anchor" href="#_1、安装启动端口转发服务" aria-label="Permalink to &quot;1、安装启动端口转发服务&quot;">​</a></h2><p>复制命令粘贴至命令行回车执行</p><p>sudo apt-get update -y sudo apt-get install redir -y</p><h2 id="_2、一键启动转发服务" tabindex="-1">2、一键启动转发服务 <a class="header-anchor" href="#_2、一键启动转发服务" aria-label="Permalink to &quot;2、一键启动转发服务&quot;">​</a></h2><p>sudo redir :转发端口 域名:端口 例如 sudo redir :1668 baidu.com:2222</p><p>查看redir当前配置命令 ps -aux | grep redir</p><p>比如鱼池转发：</p><p>sudo redir :6687 eth.f2pool.com:6688</p><p>执行后没有任何输出，表示执行成功</p><h2 id="_3、说明" tabindex="-1">3、说明： <a class="header-anchor" href="#_3、说明" aria-label="Permalink to &quot;3、说明：&quot;">​</a></h2><p>redir :6687 监听访问本服务器的6687端口，eth.f2pool.com:6688 转发到eth.f2pool.com的6688端口 到此就搭建完成了！ 连接服务器公网ip:6687即可挖矿。例如：1.2.3.4:6687</p><p>查看当前监听端口的id sudo netstat -anp |grep 6687</p><p>执行后，看到该监听端口id为1907</p><p>停止当前转发服务</p><p>sudo kill 1907</p><p>此外，若云服务器重启，转发服务也需要重新启动，重新启动命令即可</p>',20)]))}const c=e(i,[["render",p]]);export{u as __pageData,c as default};
